<template><view class="page"><xy-header title="会员资料"/><view class="wrap"><view class="card"><text>邀请码：{{profile.inviteCode||'--'}}</text><text>会员卡：{{profile.card&&profile.card.cardNo||'未开通'}}</text></view><view class="card"><text>昵称</text><input v-model="form.nickname" placeholder="请输入昵称"/><text>手机号</text><input v-model="form.mobile" type="number" placeholder="可选，用于订单联系"/></view><button class="submit" :disabled="saving" @click="save">{{saving?'保存中…':'保存资料'}}</button></view></view></template>
<script>
import{appRequest,ensureMemberSession,showRequestError}from '../../utils/api'
export default{data(){return{profile:{},form:{nickname:'',mobile:''},saving:false}},onShow(){this.load()},methods:{async load(){try{await ensureMemberSession();this.profile=await appRequest({url:'/app/me'});this.form.nickname=this.profile.nickname||'';this.form.mobile=this.profile.mobile||''}catch(e){showRequestError(e)}},async save(){this.saving=true;try{await appRequest({url:'/app/me',method:'PUT',data:this.form});uni.showToast({title:'已保存',icon:'success'})}catch(e){showRequestError(e)}finally{this.saving=false}}}}
</script>
<style scoped>.page{min-height:100vh;background:var(--xy-bg)}.wrap{padding:24rpx}.card{display:flex;flex-direction:column;gap:20rpx;margin-bottom:20rpx;padding:28rpx;border-radius:22rpx;background:#fff}.card input{padding:18rpx;border-radius:14rpx;background:var(--xy-surface-2)}.submit{background:var(--xy-primary);color:#fff}</style>
